import math
class Circle:
    def __init__(self, radius):
        self.radius = radius
    def area(self):
        return 3.14159 * self.radius ** 2
c = Circle(5)
assert abs(c.area() - 78.53975) < 0.001

class BankAccount:
    def __init__(self):
        self.balance = 0
    def deposit(self, amount):
        self.balance += amount
    def withdraw(self, amount):
        self.balance -= amount
acc = BankAccount()
acc.deposit(200)
acc.withdraw(50)
assert acc.balance == 150
